const response = $input.first().json;
const prevData = $('Build Management Pack').first().json;

let summaryText = 'AI summary not available.';

try {
  if (response.choices && response.choices.length > 0) {
    summaryText = response.choices[0].message.content || summaryText;
  } else if (response.error) {
    summaryText = `AI summary generation failed: ${response.error.message || 'Unknown error'}`;
  }
} catch (e) {
  summaryText = `AI summary parsing failed: ${e.message}`;
}

return {
  json: {
    ...prevData,
    aiSummary: summaryText,
    aiModel: response.model || 'unknown',
    aiTokensUsed: response.usage ? response.usage.total_tokens : 0,
  }
};
